public double cumulativeProbability(double x) throws MathException {
    if (Double.isInfinite(x)) {
        return x > mean ? 1.0 : 0.0;
    }

    final double dev = x - mean;
    final double scaledDev = dev / (standardDeviation * FastMath.sqrt(2.0));

    // Prevent potential issues when dealing with extreme values by using large dev approximations
    if (scaledDev > 10.0) {  // Effectively far right tail
        return 1.0;
    } else if (scaledDev < -10.0) {  // Effectively far left tail
        return 0.0;
    }

    try {
        return 0.5 * (1.0 + Erf.erf(scaledDev));
    } catch (MaxIterationsExceededException ex) {
        throw new MathException("The CDF did not converge", ex);
    }
}

public double cumulativeProbability(double x) throws MathException {
    final double dev = x - mean;
    // Use a threshold based on statistical significance rather than a hard-coded magic number
    double zScore = Math.abs(dev / standardDeviation);
    if (zScore > 8) { // Roughly corresponds to negligible probability region of normal distribution
        return x < mean ? 0.0 : 1.0;
    }
    try {
        return 0.5 * (1.0 + Erf.erf((dev) / (standardDeviation * FastMath.sqrt(2.0))));
    } catch (MaxIterationsExceededException ex) {
        // Maintain original reasoning for extreme values in failed iterations
        if (dev < 0) {
            return 0.0;
        } else {
            return 1.0;
        }
    }
}

